save.__example:
local ini = require "ini"

local t = 	{
				user1 = {
					name = "John",
					age = 38,
					sex = "male"
				},
				user2 = {
					name = "Jane",
					age = 26,
					sex = "female"
				}
			}

-- save the table content to a file in ini format
