encode.__example:
local ini = require "ini"

local t = 	{
        user1 = {
          name = "John",
          age = 38,
          sex = "male"
        },
        user2 = {
          name = "Jane",
          age = 26,
          sex = "female"
        }
      }

-- prints the table content encoded in ini format
print(ini.encode(t))
